// // This module implements a shift register that loads an 8-bit value from an input and performs serial shifting on each clock cycle. When the load signal (ld) is deasserted, the shift register will be loaded with the value from input d; otherwise, the register will shift its content right by one bit and input d will be shifted into the most significant bit position.
module top_module(
  input clk,
  input ld,
  input d,
  output reg q
);reg [7:0] shift_reg;

always @(posedge clk) begin
  if(ld) begin
    shift_reg <= d;
  end else begin
    shift_reg <= {shift_reg[6:0], d};
  end
end

assign q = shift_reg[0];

endmodule
